# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import json
from google.cloud import storage
from tempfile import NamedTemporaryFile

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    if not blob.metadata:
        print(f"No metadata found for {file_name}")
        return
    
    conversion_options = blob.metadata.get('conversion_options', '')
    output_format = blob.metadata.get('output_format', 'jpg')
    output_bucket = blob.metadata.get('output_bucket', bucket_name)
    output_prefix = blob.metadata.get('output_prefix', 'converted/')
    quality = blob.metadata.get('quality', '85')
    resize = blob.metadata.get('resize', '')
    
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    output_file_name = f"{output_prefix}{base_name}.{output_format}"
    
    with NamedTemporaryFile(delete=False, suffix=os.path.splitext(file_name)[1]) as input_temp:
        blob.download_to_filename(input_temp.name)
        input_path = input_temp.name
    
    with NamedTemporaryFile(delete=False, suffix=f'.{output_format}') as output_temp:
        output_path = output_temp.name
    
    try:
        cmd = ['convert', input_path]
        
        if resize:
            cmd.extend(['-resize', resize])
        
        if quality and output_format.lower() in ['jpg', 'jpeg', 'png']:
            cmd.extend(['-quality', quality])
        
        if conversion_options:
            options_list = conversion_options.split()
            cmd.extend(options_list)
        
        cmd.append(output_path)
        
        result = subprocess.call(cmd)
        
        if result != 0:
            print(f"ImageMagick conversion failed with exit code {result}")
            return
        
        output_bucket_obj = storage_client.bucket(output_bucket)
        output_blob = output_bucket_obj.blob(output_file_name)
        output_blob.upload_from_filename(output_path)
        
        print(f"Successfully converted {file_name} to {output_file_name}")
        
    finally:
        if os.path.exists(input_path):
            os.remove(input_path)
        if os.path.exists(output_path):
            os.remove(output_path)


def convert_image_advanced(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    if not blob.metadata:
        print(f"No metadata found for {file_name}")
        return
    
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    file_ext = os.path.splitext(file_name)[1]
    
    conversion_configs = blob.metadata.get('conversions', '[]')
    try:
        conversions = json.loads(conversion_configs)
    except json.JSONDecodeError:
        conversions = []
    
    output_bucket = blob.metadata.get('output_bucket', bucket_name)
    output_prefix = blob.metadata.get('output_prefix', 'converted/')
    
    with NamedTemporaryFile(delete=False, suffix=file_ext) as input_temp:
        blob.download_to_filename(input_temp.name)
        input_path = input_temp.name
    
    try:
        if conversions:
            for config in conversions:
                process_conversion(input_path, base_name, config, output_bucket, output_prefix, storage_client)
        else:
            default_config = {
                'format': blob.metadata.get('output_format', 'jpg'),
                'quality': blob.metadata.get('quality', '85'),
                'resize': blob.metadata.get('resize', ''),
                'options': blob.metadata.get('conversion_options', '')
            }
            process_conversion(input_path, base_name, default_config, output_bucket, output_prefix, storage_client)
    
    finally:
        if os.path.exists(input_path):
            os.remove(input_path)


def process_conversion(input_path, base_name, config, output_bucket, output_prefix, storage_client):
    output_format = config.get('format', 'jpg')
    quality = config.get('quality', '85')
    resize = config.get('resize', '')
    options = config.get('options', '')
    suffix = config.get('suffix', '')
    
    output_name = f"{base_name}{suffix}.{output_format}"
    output_file_name = f"{output_prefix}{output_name}"
    
    with NamedTemporaryFile(delete=False, suffix=f'.{output_format}') as output_temp:
        output_path = output_temp.name
    
    try:
        cmd = ['convert', input_path]
        
        if resize:
            cmd.extend(['-resize', resize])
        
        if quality and output_format.lower() in ['jpg', 'jpeg', 'png', 'webp']:
            cmd.extend(['-quality', quality])
        
        if options:
            if isinstance(options, str):
                options_list = options.split()
            else:
                options_list = options
            cmd.extend(options_list)
        
        cmd.append(output_path)
        
        result = subprocess.call(cmd)
        
        if result != 0:
            print(f"ImageMagick conversion failed for {output_name} with exit code {result}")
            return
        
        bucket_obj = storage_client.bucket(output_bucket)
        output_blob = bucket_obj.blob(output_file_name)
        output_blob.upload_from_filename(output_path)
        
        print(f"Successfully converted to {output_file_name}")
        
    finally:
        if os.path.exists(output_path):
            os.remove(output_path)